    const source = Array.isArray(jobs) ? jobs : Object.values(feature.exportJobs);
    const normalized = source
      .filter((job) => job && job.jobId)
      .sort((left, right) => Number(right.requestedAtMs || 0) - Number(left.requestedAtMs || 0))
      .slice(0, ADMIN_TERMINAL_EXPORT_HISTORY_LIMIT);
    const persisted = normalized.map((job) => ({ jobId: job.jobId, status: job.status || "queued", fileName: job.fileName || "CSV export", requestedAt: job.requestedAt || "", requestedAtMs: Number(job.requestedAtMs || Date.now()), actionName: job.actionName || "", gameId: job.gameId || "", message: job.message || "", polling: false }));
    try { window.localStorage?.setItem?.(getAdminTerminalExportHistoryStorageKey(), JSON.stringify(persisted)); } catch (_) {}
    return normalized;
