    if (statusNode) { statusNode.textContent = statusLabel; statusNode.className = `is-status ${String(statusLabel).toLowerCase().includes("late") ? "is-late" : String(statusLabel).toLowerCase().includes("present") ? "is-present" : ""}`; }
