function getAttendanceHistoryInputDate(rawDate) {
    const raw = String(rawDate || "").trim();
    const today = new Date();
    const iso = (date) => new Date(date.getTime() - date.getTimezoneOffset() * 60000).toISOString().slice(0, 10);
    if (!raw || raw.toLowerCase() === "today") return iso(today);
    if (raw.toLowerCase() === "yesterday") { const date = new Date(today); date.setDate(date.getDate() - 1); return iso(date); }
    const parsed = new Date(raw); return Number.isFinite(parsed.getTime()) ? iso(parsed) : "";
  }
function getAttendanceHistoryAbsoluteDate(rawDate) {
    const raw = String(rawDate || "").trim();
    if (!raw) return "—";
    const base = new Date();
    if (raw.toLowerCase() === "yesterday") base.setDate(base.getDate() - 1);
    const parsed = ["today", "yesterday"].includes(raw.toLowerCase()) ? base : new Date(raw);
    return Number.isFinite(parsed.getTime()) ? parsed.toLocaleDateString(undefined, { year: "numeric", month: "short", day: "numeric" }) : raw;
  }
