  function renderMarketplaceGlobalTradeHistory(trades = [], securities = []) {
    const securityById = new Map((Array.isArray(securities) ? securities : []).flatMap((security) => [
      [String(security.id || security.assetId || ""), security],
      [String(security.symbol || ""), security]
    ]).filter(([key]) => key));
    const normalizedTrades = (Array.isArray(trades) ? trades : []).slice(0, 30).map((trade) => {
      const assetKey = String(trade?.assetId || trade?.marketAssetId || trade?.symbol || trade?.ticker || "");
      const security = securityById.get(assetKey) || {};
      const sideRaw = String(trade?.side || trade?.type || trade?.action || "Trade").toLowerCase();
      const side = sideRaw.includes("sell") ? "Sold" : sideRaw.includes("buy") ? "Bought" : titleCaseMarketplaceFacet(sideRaw);
      const player = trade?.playerName || trade?.displayName || trade?.studentName || trade?.actorName || "Player";
      const quantity = trade?.quantity ?? trade?.qty ?? trade?.shares ?? "—";
      const symbol = trade?.symbol || trade?.ticker || security.symbol || "—";
      const price = trade?.price ?? trade?.executionPrice ?? trade?.amount ?? security.price ?? "—";
      const currency = trade?.currency || security.currency || "NRC";
      const timestamp = trade?.executedAt || trade?.createdAt || trade?.timestamp || trade?.time;
      let time = "—";
      if (timestamp) {
        const parsed = new Date(timestamp);
        time = Number.isNaN(parsed.getTime()) ? String(timestamp) : parsed.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
      }
      return { time, player, side, quantity, symbol, price, currency };
    });
    return `
      <section class="admin-terminal-marketplace-orders is-global-trade-history" aria-label="Global recent trade history">
        <header><span>Global Ledger</span><strong>Recent trade history</strong><small>Latest backend-confirmed executions across all players.</small></header>
        <div data-marketplace-trade-history>
          ${normalizedTrades.length ? normalizedTrades.map((trade) => `<article><span>${escapeHtml(trade.time)}</span><strong>${escapeHtml(trade.player)} ${escapeHtml(trade.side.toLowerCase())} ${escapeHtml(trade.quantity)} ${escapeHtml(trade.symbol)}</strong><small>${renderCurrencyAmount(trade.price, trade.currency)} · all players</small></article>`).join("") : `<p class="admin-terminal-marketplace-trade-empty admin-terminal-ledger-empty-state">No recent trade history.</p>`}
        </div>
      </section>`;
  }
