function getAdminHelpArticles() {
    const model = getAdminTerminalCurrentModel();
    const backend = Array.isArray(model?.helpArticles) ? model.helpArticles.filter((article) => article && typeof article === "object") : [];
    if (backend.length) return backend.map((article, index) => ({ id: String(article.id || article.slug || `help-${index + 1}`), category: article.category || "Help", title: article.title || "Untitled article", summary: article.summary || article.description || "", duration: article.duration || "", screenshot: article.screenshot || article.imageUrl || "", screenshotAlt: article.screenshotAlt || article.title || "Help article screenshot", screenshotCaption: article.screenshotCaption || "", relatedSection: article.relatedSection || "AdminHelp", steps: Array.isArray(article.steps) ? article.steps.map((step) => Array.isArray(step) ? step : [step.title || "Step", step.text || step.description || ""]) : [], tips: Array.isArray(article.tips) ? article.tips : [] }));
    return Object.entries(ADMIN_TERMINAL_HELP_ARTICLES).map(([id, article]) => ({ id, ...article }));
  }
function renderAdminHelpArticleModal(articleId = "") {
    const articles = getAdminHelpArticles();
    const article = articles.find((item) => String(item.id) === String(articleId)) || articles[0];
    if (!article) return renderModalShell({ id: "admin-help-unavailable", tone: "cyan", eyebrow: "Help", title: "Article unavailable", body: `<p>No help article was returned.</p>` });
    return renderModalShell({ id: `admin-help-${String(article.id).replace(/[^a-z0-9-]/gi, "-")}`, tone: "cyan", eyebrow: article.category, title: article.title, modalClass: "admin-terminal-help-article-modal", body: `<article class="admin-terminal-help-article"><header><div>${renderAdminStatusPill(article.category, "cyan")}${article.duration ? renderAdminStatusPill(article.duration, "neutral") : ""}</div><p>${escapeHtml(article.summary || "")}</p></header>${article.screenshot ? `<figure><img src="${escapeAdminTerminalResourceUrl(article.screenshot)}" alt="${escapeHtml(article.screenshotAlt || "")}" loading="eager" /><figcaption>${escapeHtml(article.screenshotCaption || "")}</figcaption></figure>` : ""}<section><span>Step-by-step</span><ol>${(article.steps || []).map(([title, text]) => `<li><div><strong>${escapeHtml(title)}</strong><p>${escapeHtml(text)}</p></div></li>`).join("") || "<li>No steps were returned.</li>"}</ol></section>${(article.tips || []).length ? `<aside><span>Good practice</span><ul>${article.tips.map((tip) => `<li>${escapeHtml(tip)}</li>`).join("")}</ul></aside>` : ""}</article>` });
  }
