  async function copyTerminalShareText(text, successMessage = "Copied.") {
    const value = String(text || "");
    try {
      if (navigator.clipboard?.writeText) {
        await navigator.clipboard.writeText(value);
        showAdminTerminalStatus("ok", successMessage);
        return true;
      }
    } catch (_) {
    }
    try {
      const input = document.createElement("textarea");
      input.value = value;
      input.setAttribute("readonly", "readonly");
      input.style.position = "fixed";
      input.style.left = "-9999px";
      input.style.top = "0";
      document.body.appendChild(input);
      input.select();
      const copied = document.execCommand?.("copy");
      input.remove();
      showAdminTerminalStatus(copied ? "ok" : "warn", copied ? successMessage : "Copy unavailable. Select the summary manually.");
      return Boolean(copied);
    } catch (_) {
      showAdminTerminalStatus("warn", "Copy unavailable. Select the summary manually.");
      return false;
    }
  }
