  function isCurrentAdminGameSwitch(switchContext = null) {
    const feature = window.Econovaria.features.adminOverviewTerminal;
    return Boolean(switchContext?.switchId && Number(switchContext.switchId) === Number(feature.gameSwitchSequence || 0));
  }
  async function confirmAdminGameSwitchWithRetryLegacyV604(switchContext, action, attempt = 0) {
    const feature = window.Econovaria.features.adminOverviewTerminal;
    if (!isCurrentAdminGameSwitch(switchContext)) return { ok: false, stale: true, reason: "superseded-game-switch" };
    const result = await requestAdminTerminalApiAction("switch-admin-game", action, { refresh: false });
    if (!isCurrentAdminGameSwitch(switchContext)) return { ok: false, stale: true, reason: "superseded-game-switch" };
    const status = Number(result?.status || 0);
    const definitiveClientFailure = status >= 400 && status < 500 && ![408, 425, 429].includes(status);
    if (result?.ok) {
      feature.pendingGameSwitch = null;
      feature.confirmedGame = { ...switchContext.nextGame };
      feature.confirmedGameModel = { ...getAdminTerminalCurrentModel() };
      await loadAdminTerminalPageData("Overview", { silent: true, force: true, noLoadingRender: true });
      if (!isCurrentAdminGameSwitch(switchContext)) return { ok: false, stale: true, reason: "superseded-game-switch" };
      showAdminTerminalStatus("ok", `${switchContext.nextGame.name} is now active.`);
      return result;
    }
    if (["missing-stable-id", "csrf-token-missing", "reauth-required"].includes(result?.reason) || definitiveClientFailure) {
      feature.pendingGameSwitch = null;
      restoreAdminGameSwitch(switchContext);
      showAdminTerminalStatus("warn", "The game could not be switched. The previous game remains active.");
      return result;
    }
    if (attempt >= 2) {
      feature.pendingGameSwitch = null;
      restoreAdminGameSwitch(switchContext);
      showAdminTerminalStatus("warn", "Game switching could not be confirmed after three attempts. The previous game was restored.");
      return result;
    }
    feature.pendingGameSwitch = { switchId: switchContext.switchId, switchContext, action, attempt: attempt + 1 };
    showAdminTerminalStatus("warn", `${switchContext.nextGame.name} is awaiting backend confirmation. Retrying automatically.`);
    await new Promise((resolve) => window.setTimeout(resolve, 1200 * (attempt + 1)));
    if (!isCurrentAdminGameSwitch(switchContext)) return { ok: false, stale: true, reason: "superseded-game-switch" };
    return confirmAdminGameSwitchWithRetry(switchContext, action, attempt + 1);
  }
