    detail.dataset.adminLogSelectedSummary = data.logSummary || "System event recorded.";
    detail.dataset.adminLogSelectedSource = source;
    detail.dataset.adminLogSelectedBefore = data.logBefore || "—";
    detail.dataset.adminLogSelectedAfter = data.logAfter || "—";
