    activeChart.querySelectorAll("[data-marketplace-compare-line]").forEach((line) => line.classList.toggle("is-active", line.dataset.marketplaceCompareLine === compare));
    const labelNode = activeChart.querySelector("[data-marketplace-compare-label]"); if (labelNode) labelNode.textContent = `Compare: ${label}`;
