    const initialModel = getAdminTerminalCurrentModel();
    if (!isAdminTerminalDemoDataEnabled() && feature.authState?.state !== "ready") return { ok: false, reason: "session-bootstrap-required" };
    const area = getAdminTerminalSectionPermissionArea(normalized);
    if (!canAdminTerminalAccessArea(area, "read", initialModel)) return { ok: false, reason: "permission-denied", section: normalized };
    const readKeys = getAdminTerminalReadKeysForSection(normalized).filter((name) => Boolean(ADMIN_TERMINAL_API_READ_ENDPOINTS[name]));
    const gameId = getAdminTerminalGameIdentifier(initialModel);
    const cacheKey = `${gameId}:${normalized}`;
