    const cached = feature.apiReadCache[cacheKey]; const cachedAt = cached?.loadedAt ? new Date(cached.loadedAt).getTime() : 0;
    if (!options.force && cachedAt && Date.now() - cachedAt < Number(options.cacheTtlMs ?? ADMIN_TERMINAL_READ_CACHE_TTL_MS)) return cached;
    if (feature.apiReadLoading[cacheKey]) return feature.apiReadLoading[cacheKey];
